 17→package com.ichi2.anki
 18→
 19→import android.content.Context
 20→import android.content.Intent
 21→import android.os.Bundle
 22→import android.speech.RecognitionListener
 23→import android.speech.RecognizerIntent
 24→import android.speech.SpeechRecognizer
 25→import com.ichi2.utils.Permissions.canRecordAudio
 26→
 27→class JavaScriptSTT(private val context: Context) {
 28→    private var speechRecognizer: SpeechRecognizer? = null
 29→    private var recognitionCallback: SpeechRecognitionCallback? = null
 30→    private var language: String? = null
 31→
 32→    interface SpeechRecognitionCallback {
 33→        fun onResult(results: List<String>)
 34→        fun onError(errorMessage: String)
 35→    }
 36→
 37→    fun setLanguage(lang: String): Boolean {
 38→        this.language = lang
 39→        return true
 40→    }
 41→
 42→    fun setRecognitionCallback(callback: SpeechRecognitionCallback) {
 43→        this.recognitionCallback = callback
 44→    }
 45→
 46→    fun start(): Boolean {
 47→        if (!canRecordAudio(context)) {
 48→            recognitionCallback?.onError("Record audio permission not granted.")
 49→            return false
 50→        }
 51→
 52→        if (!SpeechRecognizer.isRecognitionAvailable(context)) {
 53→            recognitionCallback?.onError("Speech recognition is not available on this device.")
 54→            return false
 55→        }
 56→
 57→        speechRecognizer = SpeechRecognizer.createSpeechRecognizer(context)
 58→        speechRecognizer?.setRecognitionListener(createRecognitionListener())
 59→
 60→        val intent = Intent(RecognizerIntent.ACTION_RECOGNIZE_SPEECH)
 61→        intent.putExtra(RecognizerIntent.EXTRA_LANGUAGE, language)
 62→        intent.putExtra(RecognizerIntent.EXTRA_LANGUAGE_MODEL, RecognizerIntent.LANGUAGE_MODEL_FREE_FORM)
 63→
 64→        try {
 65→            speechRecognizer?.startListening(intent)
 66→            return true
 67→        } catch (e: Exception) {
 68→            recognitionCallback?.onError("Error starting speech recognition.")
 69→        }
 70→        return false
 71→    }
 72→
 73→    fun stop(): Boolean {
 74→        speechRecognizer?.stopListening()
 75→        return true
 76→    }
 77→
 78→    private fun createRecognitionListener(): RecognitionListener {
 79→        return object : RecognitionListener {
 80→            override fun onReadyForSpeech(params: Bundle?) {}
 81→
 82→            override fun onBeginningOfSpeech() {}
 83→
 84→            override fun onRmsChanged(rmsdB: Float) {}
 85→
 86→            override fun onBufferReceived(buffer: ByteArray?) {}
 87→
 88→            override fun onEndOfSpeech() {}
 89→
 90→            override fun onError(error: Int) {
 91→                val errorMessage = when (error) {
 92→                    SpeechRecognizer.ERROR_AUDIO -> "Audio error"
 93→                    SpeechRecognizer.ERROR_CLIENT -> "Client error"
 94→                    SpeechRecognizer.ERROR_INSUFFICIENT_PERMISSIONS -> "Insufficient permissions"
 95→                    SpeechRecognizer.ERROR_NETWORK -> "Network error"
 96→                    SpeechRecognizer.ERROR_NETWORK_TIMEOUT -> "Network timeout"
 97→                    SpeechRecognizer.ERROR_NO_MATCH -> "No match found"
 98→                    SpeechRecognizer.ERROR_RECOGNIZER_BUSY -> "Recognition service busy"
 99→                    SpeechRecognizer.ERROR_SERVER -> "Server error"
100→                    SpeechRecognizer.ERROR_SPEECH_TIMEOUT -> "Speech timeout"
101→                    else -> "Unknown error"
102→                }
103→                recognitionCallback?.onError(errorMessage)
104→            }
105→
106→            override fun onResults(results: Bundle?) {
107→                val matches = results?.getStringArrayList(SpeechRecognizer.RESULTS_RECOGNITION)
108→                if (!matches.isNullOrEmpty()) {
109→                    recognitionCallback?.onResult(matches)
110→                } else {
111→                    recognitionCallback?.onError("No speech recognition results found.")
112→                }
113→            }
114→
115→            override fun onPartialResults(partialResults: Bundle?) {}
116→
117→            override fun onEvent(eventType: Int, params: Bundle?) {}
118→        }
119→    }
120→}
